INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2032_L021$$, 2026, $$Army Tactical Missile System (ATACMS) is the United States (U.S.) Army's primary 24/7, all weather, and surface-to-surface artillery precision missile used by current and future Combatant Commanders to
 shape the battlefield with long-range fires against hard and soft stationary targets in open, complex, and urban environments. The missile provides the Combatant Commanders with a 24/7 all-weather 300
 kilometers (km) long-range fires capability to attack high-payoff, time-sensitive targets without placing aircraft and crews at risk. It's precision accuracy, along with the absence of potential duds and reduced
 lethal radii, mitigate the warfighter's collateral damage concerns against hard and soft targets in complex and urban environments.

 Justification:
 There is no funding for FY 2027.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                           Date: April 2026
