INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L007$$, 2027, $$The Stryker (Mod) funding line will fund procurement of Stryker Double-V Hull A1 Commander's Vehicles and related fielding costs to provide Command Post Integrated Infrastructure (CPI2) to the Stryker
 Brigade Combat Team (SBCT). As one of the Army's top network priorities, CPI2 technologies will be integrated with legacy mission command systems, onto a variation of the Stryker Commander's Vehicle.
 The integrated systems will provide a mobile and survivable command post solution to the Stryker Brigade Combat Team (SBCT), enabling on-the-move mission command across wider ranges at both the
 Brigade and Battalion echelons.

 Justification:
 There is no Fiscal Year 2027 budget request for this funding line.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                          Date: April 2026
