INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L008$$, 2027, $$The Bradley Fire Support Team (BFIST) vehicle replaced the aging M981 Fire Support Vehicle used by the Fire Support Team (FIST) in the Armored Brigade Combat Teams (ABCT). The BFIST contributes to
 success on the battlefield by accurately locating and designating targets and then combining this information to develop and execute fire support plans. The BFIST allows fire support operations to be performed
 on the battlefield in vehicles with the same signature, survivability, and mobility as the other Bradley Fighting Vehicles (BFV) in the maneuver units it supports. There are 303 Bradley Fire Support Team (BFIST)
 vehicles fielded with three variants: M7A4 BFIST, A3 BFIST with Fire Support Sensor System (FS3), and M7 BFIST Situation Awareness (SA). This supports funding for the components, application, and
 engineering and logistics support of improvements designed to resolve problems identified in the field, engineering support related to production, improved safety, integrate new equipment, develop and integrate
 mod kits, address obsolescence issues, and bring the vehicle into compliance with transportability and recovery requirements.

 All three variants enable company Fire Support Teams (FIST) and company fire support officers to plan, coordinate and execute timely, accurate indirect artillery and mortar fires. The Fire Support Sensor System
 (FS3) on all vehicles provides automated enhanced surveillance, target acquisition, target identification, target designation, target tracking, position location, and communications functionality under armor while
 mounted and target acquisition and designation while dismounted. All variants are being upgraded to include Fire Observer Software (FOS) on the Mounted Family of Computer System (MFoCS), TALIN 5000
 Inertial Navigation Unit (INU); and Target Accuracy upgrades to meet Category I (CAT I) Target Location Error (TLE) specifications - the highest level TLE obtainable. After upgrades are completed, all Bradley
 Fire Support Team (BFIST) vehicles will meet the Operational Requirements Document (ORD) objective requirements.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                            Date: April 2026
