INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L017$$, 2026, $$The M1110 Joint Assault Bridge (JAB) replaces the existing M104 Wolverine and M48A5/M60 chassis-based Armored Vehicle Launched Bridge (AVLB) to meet current maneuver force survivability, suitability
 and supportability requirements and provide the only gap crossing capabilities to the armored forces during combat operations. The JAB is an M1A1 Abrams chassis-based engineer vehicle with a M1A2
 Abrams heavy suspension that launches and retrieves the 18.3-meter Heavy Assault Scissor Bridge (HASB), which is currently rated at Military Load Classification (MLC) 115 Tons. The JAB system is employed
 with Army Armored Brigade Combat Teams (ABCT) in the Brigade Engineer Battalions (BEB), Engineer Mobility Augmentation Companies (MAC), and Combat Engineer Companies - Armored (CEC-A). The
 production / acquisition strategy includes a partnership with Anniston Army Depot (ANAD) for the production of the Abrams Chassis and HASB; the ANAD effort includes the upgrade of the HASB to MLC-115.
 The JAB prime contractor will produce and integrate the Bridge Launch Mechanism (BLM) Add on Armor (AoA) with Mission Ready Tablet (MRT). There are 120 JAB systems in Army inventory which must be
 retrofitted, based on Modification Work Orders (MWO), with BLM AoA and the MRT in order to pure fleet the JAB. The JAB program will employ modifications to correct safety deficiencies, increase mission
 capabilities, extend the useful life, improve supportability, upgrade existing technology, increase efficiency, address obsolescence, improve readiness, and to meet new legal and regulatory requirements.
 The JAB Common Driver Trainer (Simulators) will be employed to support training efforts for the JAB program. The JAB program completed Initial Operational Test (IOT) in November 2020, received Type
 Classification-Standard (TC-STD) and Full Rate Production (FRP) approval in March 2021, and achieved Full Materiel Release on April 2023.

