INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L069$$, 2026, $$The Fuels Support Equipment (FSE) program funds for the procurement of Fuels Operational Readiness Capability Equipment (FORCE). It provides the capability to receive, store, and issue petroleum products
 and support aircraft generation in austere locations where fixed systems do not exist or which require augmentation. This equipment is part of the Air Force's prepositioned war reserve materiel (WRM) and will be
 managed in accordance with 10 U.S.C. 2229, Strategic Policy on Prepositioning of Materiel and Equipment.

 FORCE Servicing (FS), Receipt (RC) and Sustainment (SC) is a deployable modular fuel system that can provide joint capability to fuel aircraft and support equipment at forward locations. The FORCE system
 can be configured to perform limited aircraft fueling missions or to sustain massive daily fueling requirements for months. FORCE is capable of receiving, transferring, and issuing fuel at a throughput rate of 900
 Gallons per Minute (GPM). The individual pieces of equipment that comprise the FORCE system provide stand-alone or mix-and-match capability for almost any fuel transfer or aircraft refueling scenario. The full
 capability mission of the complete FORCE System, when used in conjunction with fabric fuel bladders, provides a deployable, above ground, constant pressure, flow-on demand fueling system for aircraft, i.e., a
 hydrant-type fueling system.

 Aerial Bulk Fuel Delivery System (ABFDS)/Agile Fueling System (AFS): Designed for aerial delivery of fuel to locations where other methods of transportation are impractical. It enables aircraft to rapidly transport
 fuel to locations close to or behind enemy lines and is a key component to the AF Special Operations community and their ability to complete Forward Area Refueling Point missions.

 FSE Lab Equipment contain a variety of high-tech equipment such as flash point testers, density meters, and oxidation stability analyzers to test samples from fuel tanks for contaminants.

 3K Collapsible Fuel Tanks (CFT) are specifically designed to be loaded on military aircraft and withstand the critical demands put on them during flight operations, in conjunction with the ABFDS they provide the
 ability to transfer fuel from the aircraft storage bladder while aircraft engines are running.

 Fuel Bladders: Collapsible Fuel Tanks (CFT) or more commonly referred to as fuel bladders provide fuel storage capabilities at austere or forward operating locations where infrastructure is either inadequate or
 non-existent. Bladders sizes range from 10K, 50K and 210K gallons of fuel storage, these bladders are capable of holding a multitude of petroleum products to support both air and ground operations. Collapsible
 fuel tanks are used with Fuels Operational Readiness Capability Equipment (FORCE) to support various aircraft systems at forward operating locations.

 LOX/Lin Tanks, are deployable liquid oxygen/liquid nitrogen storage tanks that can receive, store, and issue liquid oxygen or nitrogen products to service carts or smaller tanks. Provides bulk storage capacity
 and is used to fill smaller cryogenic equipment (8-Cylinder trailers, 50-Gallon LOX Tank) and aircraft.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":69,"src_title":"Fuels Support Equipment (FSE)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 779, 779, $$fccd178d38b3458a$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
