INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L027$$, 2026, $$The M2A1 .50 Caliber Machine Gun is an automatic, belt-fed, recoil-operated, and air-cooled crew-served weapon. It mounts on the M205 tripod and on most vehicles, and serves as an anti-personnel and anti-
 aircraft weapon. It is highly effective against light armored vehicles, low-and slow-flying aircraft, and small boats. The M2A1 provides automatic weapon suppressive fire for offensive and defensive purposes.
 It is capable of single-shot and automatic fire. The M2A1 provides enhancements to allow the Soldier to quickly change barrels without the need to reset the headspace and timing while also reducing the visible
 muzzle flash.

 Justification:
 There is no Fiscal Year 2027 budget request for this funding line.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                           Date: April 2026
