INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L028$$, 2027, $$The Mortar Systems program supports the production of 60mm, 81mm, 120mm mortar weapon systems, and future variants/modernized systems; including mortar mobility system and associated supporting
 subsystems, Basic Issue Items (BII), Additional Authorized List (AAL) items, and tool kits. These mortar weapon systems, along with the associated equipment and subsystem components support both the
 mounted and dismounted vehicle platforms in the Infantry Brigade Combat Teams (IBCTs)/ Mobile Brigade Combat Teams (MBCTs), Armor Brigade Combat Teams (ABCTs), and Stryker Brigade Combat Teams
 (SBCTs). The mobility systems enable rapid emplacement and displacement of mortar weapon systems, when hosted on current and future vehicle platforms. The 60mm, 81mm and 120mm mortar weapon
 systems and components fulfill current and future Army Acquisition Objective (AAO) requirements, urgent requirements, increase of Army reorganization and Army stand up unit requirements, and address mortar
 system safety and obsolescence concerns.

 Justification:
 Fiscal Year (FY) 2027 funding in the amount of $3.575 million will support the procurement of two (2) each M121 120mm mortar weapon systems, required subsystem components, Modified Work Order (MWO)
 kits, Basic Issue Item (BII) kits, Engineering Change Proposals (ECPs), and updates required to the applicable Technical Data Packages (TDPs). Funding will also support efforts to address technical issues and
 obsolescence related to weapon system safety, special force requirements and modernized mounted and dismounted platforms in the Armor Brigade Combat Teams (ABCTs), as well as Armor Multi-Purpose
 Vehicle (AMPV) requirements. Funding is to support 120mm mortar weapon systems resulting from Army ABCT reorganization from two Battalions per Brigade to three Battalions per Brigade as well as the
 increase in the Army Acquisition Objective (AAO) for new stand-up units.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                                      Date: April 2026
