INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L033$$, 2026, $$This funding line is directly aligned to the Army Soldier Lethality Modernization Priority.

 Next Generation Squad Weapons (NGSW) is a family of products that includes the XM8 Carbine, M7 Rifle and M250 Automatic Rifle that integrate with advanced Fire Control and family of 6.8mm ammunition.
 The XM8 Carbine, M7 Rifle and M250 Automatic Rifle are the planned replacements for the M4 Carbine and M249 Squad Automatic Weapon for individual soldiers, squads, and/or platoons, capable of defeating
 protected and unprotected threats. The XM8 Carbine, M7 Rifle and M250 Automatic Rifle ensure increased lethality against a broad spectrum of targets beyond current/legacy weapon capabilities; increased
 range, accuracy, and probability of hit; reduced engagement time; suppressed flash/sound signature; and improved controllability and mobility. The XM8 Carbine is a lightweight, short-barrel variant of the M7
 Rifle.

 The Fire Control is an advanced individual fire control device along with optics, sights, lasers, and other enablers that supports the XM8 Carbine, M7 Rifle, M250 Automatic Rifle and other individual squad
 weapon systems. The Fire Control increases the probability of hit and decreases engagement time through a variable-powered direct view optic with integrated range finder, ballistic calculator, and digital display
 capable of providing an adjusted aim point. The Fire Control utilizes open architecture to deliver to an initial augmented core capability followed by increasing increments of capability over time as technology
 matures and evolves.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                               Date: April 2026
