INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L052$$, 2026, $$JOINT COMMUNICATION SUPPORT ELEMENT (JCSE): Aligned under Joint Enabling Capabilities Command (JECC), US Transportation Command (USTRANSCOM) - JCSE is the only Department of Defense
 (DOD) organization specifically formed that provides crisis and contingency communications to meet the operational support needs of the Joint Chiefs of Staff (JCS), Combatant Commands (CC), DOD agencies
 and non-DOD agencies. JCSE mission is to provide rapidly deployable, en route, early entry, and scalable coalition command, control, computers, intelligence, surveillance, and reconnaissance (C4ISR)
 capability to CCs and other agencies as directed to facilitate rapid establishment and transitions of Joint Forces Headquarters (JFHQs) and bridge joint communications requirements. JCSE seamlessly scales
 C4ISR support for conventional or unconventional JFHQs. JCSE has a robust 24/7 reach back capability through its Global Enterprise Network and has access to a full range of DOD and commercial networks.

 To consistently deliver relevant state of the art technology solutions to meet emergent Combatant Commands (CC) operational communications requirements, JCSE executes the Modernization Program as
 outlined in Director, Joint Staff Memorandum (DJSM) 0148-20 whereby services have validated program requirements to support JCSE's Modernization Program. Per Defense Planning Guidance and DJSM
 0148-20, the Air Force agreed to fund a 1/3rd fair share of JCSEs validated Modernization Program. JCSE's Modernization Program is based on CC and Service Components requirements and emerging
 technologies. The Services influence JCSEs spending plan through recommendations in concert with Major Defense Acquisition Program (MDAP) schedules, ensuring the Service monies meet Joint Service
 Requirements.

 Funding for this exhibit is contained in PE 0207422F, Deployable Command Control and Communications Systems.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":52,"src_title":"Joint Communications Support Element (JCSE)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 533, 533, $$d8fb8b7b39e99cf3$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L046$$, 2026, $$The Modular Handgun System (MHS) supports the Army Modernization priorities (Build a More Lethal Force) through enhancement of Joint Lethality in contested environments by minimizing and eliminating
 erosion of close combat capability relative to peer competitors in complex terrain. Currently, the M9 Semi-Automatic Pistol, which has been utilized as the Department of Defense's personal defense weapon
 since 1985, is being replaced by the new M17 Full Size Modular Handgun. The M18 Compact Size Modular Handgun replaces M11 Handguns. The Modular Handgun System is a Commercial Off the Shelf/
 Non-Developmental Item (COTS/NDI) which delivers a more capable system (weapon, ammo and magazines) consistent with the planned force structure and emerging operational needs of the Army. The
 Modular Handgun System addresses M9 Pistol and M11 Pistol shortcomings with improved lethality, target acquisition, ergonomics, reliability, durability, and maintainability. The Modular Handgun System is
 ambidextrous capable and accommodates 5th-95th percentile users via modular grips and access to all controls with one hand.

 Justification:
 There is no Fiscal Year 2027 budget request for this funding line.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L.110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                           Date: April 2026
