INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L102$$, 2026, $$The Enhanced Portable Inductive Artillery Fuze Setter (EPIAFS) program supports the Army's Field Artillery modernization objectives and is a critical system required to enable setting with current and future
 Precision Guided Munitions (PGMs) and Fuzes, as well as 155mm weapon system platforms. The EPIAFS systems provide direct set capability to integrate with modernized ammunition, electronics/hardware,
 enabling new data requirements and software updates. These updates provide new initialization data sets to support both legacy and future platforms, precision artillery projectiles and precision fuzes. Future
 PGMs and Fuzes will incorporate guidance technologies that will require more data for initialization in less time to support higher rates of fire providing overmatching capability.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                            Date: April 2026
